import React, { useEffect, useState } from "react";
import Sidebar from "../components/Sidebar";
import Navbar from "../components/Navbar";
import API from "../api";

function DoctorsPage() {
  const [doctors, setDoctors] = useState([]);
  const [form, setForm] = useState({
    name: "",
    specialization: "",
    photo: "",
    description: "",
    experience: "",
    fees: "",
    hospital: ""
  });
  const [editId, setEditId] = useState(null);

  useEffect(() => {
    fetchDoctors();
  }, []);

  const fetchDoctors = async () => {
    try {
      const res = await API.get("/doctors");
      setDoctors(res.data);
    } catch (error) {
      console.error("Failed to fetch doctors");
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      if (editId) {
        await API.put(`/doctors/${editId}`, form);
        alert("Doctor updated successfully");
      } else {
        await API.post("/doctors", form);
        alert("Doctor added successfully");
      }

      setForm({
        name: "",
        specialization: "",
        photo: "",
        description: "",
        experience: "",
        fees: "",
        hospital: ""
      });

      setEditId(null);
      fetchDoctors();
    } catch (error) {
      alert(error.response?.data?.error || "Operation failed");
    }
  };

  const handleEdit = (doctor) => {
    setForm({
      name: doctor.name || "",
      specialization: doctor.specialization || "",
      photo: doctor.photo || "",
      description: doctor.description || "",
      experience: doctor.experience || "",
      fees: doctor.fees || "",
      hospital: doctor.hospital || ""
    });

    setEditId(doctor.id);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this doctor?")) return;

    try {
      await API.delete(`/doctors/${id}`);
      fetchDoctors();
    } catch (error) {
      alert("Delete failed");
    }
  };

  return (
    <div className="dashboard-layout">
      <Sidebar role="admin" />

      <div className="main-content">
        <Navbar
          title="Doctors Management"
          subtitle="Add, edit and manage all available specialists"
        />

        <div className="form-box mb-4">
          <h4>{editId ? "Edit Doctor" : "Add New Doctor"}</h4>

          <form onSubmit={handleSubmit}>
            <div className="row mt-3">
              <div className="col-md-6 mb-3">
                <label>Doctor Name</label>
                <input
                  type="text"
                  className="form-control"
                  value={form.name}
                  onChange={(e) => setForm({ ...form, name: e.target.value })}
                  required
                />
              </div>

              <div className="col-md-6 mb-3">
                <label>Specialization</label>
                <input
                  type="text"
                  className="form-control"
                  value={form.specialization}
                  onChange={(e) =>
                    setForm({ ...form, specialization: e.target.value })
                  }
                  required
                />
              </div>

              <div className="col-md-6 mb-3">
                <label>Photo URL</label>
                <input
                  type="text"
                  className="form-control"
                  value={form.photo}
                  onChange={(e) => setForm({ ...form, photo: e.target.value })}
                  placeholder="https://..."
                />
              </div>

              <div className="col-md-6 mb-3">
                <label>Description</label>
                <input
                  type="text"
                  className="form-control"
                  value={form.description}
                  onChange={(e) =>
                    setForm({ ...form, description: e.target.value })
                  }
                  placeholder="Short doctor bio"
                />
              </div>

              <div className="col-md-4 mb-3">
                <label>Experience</label>
                <input
                  type="text"
                  className="form-control"
                  value={form.experience}
                  onChange={(e) =>
                    setForm({ ...form, experience: e.target.value })
                  }
                  placeholder="8 Years"
                />
              </div>

              <div className="col-md-4 mb-3">
                <label>Fees</label>
                <input
                  type="text"
                  className="form-control"
                  value={form.fees}
                  onChange={(e) => setForm({ ...form, fees: e.target.value })}
                  placeholder="₹800"
                />
              </div>

              <div className="col-md-4 mb-3">
                <label>Hospital</label>
                <input
                  type="text"
                  className="form-control"
                  value={form.hospital}
                  onChange={(e) =>
                    setForm({ ...form, hospital: e.target.value })
                  }
                  placeholder="City Care Hospital"
                />
              </div>
            </div>

            <button className="btn btn-premium">
              {editId ? "Update Doctor" : "Add Doctor"}
            </button>
          </form>
        </div>

        <div className="row g-4">
          {doctors.length > 0 ? (
            doctors.map((doctor) => (
              <div className="col-md-4" key={doctor.id}>
                <div className="doctor-card">
                  <img
                    src={
                      doctor.photo
                        ? doctor.photo
                        : `https://via.placeholder.com/400x250?text=${encodeURIComponent(
                            doctor.name || "Doctor"
                          )}`
                    }
                    alt={doctor.name}
                    style={{
                      width: "100%",
                      height: "250px",
                      objectFit: "cover",
                      borderRadius: "18px"
                    }}
                  />

                  <div className="mt-3">
                    <h5>{doctor.name}</h5>
                    <p className="text-primary fw-semibold">
                      {doctor.specialization}
                    </p>
                    <p className="text-muted">{doctor.description}</p>

                    <p className="mb-1">
                      <strong>Experience:</strong> {doctor.experience || "N/A"}
                    </p>
                    <p className="mb-1">
                      <strong>Fees:</strong> {doctor.fees || "N/A"}
                    </p>
                    <p className="mb-3">
                      <strong>Hospital:</strong> {doctor.hospital || "N/A"}
                    </p>

                    <button
                      className="action-btn btn-edit"
                      onClick={() => handleEdit(doctor)}
                    >
                      Edit
                    </button>

                    <button
                      className="action-btn btn-delete"
                      onClick={() => handleDelete(doctor.id)}
                    >
                      Delete
                    </button>
                  </div>
                </div>
              </div>
            ))
          ) : (
            <div className="col-12">
              <div className="dashboard-card text-center py-5">
                <h4>No Doctors Added Yet</h4>
                <p className="text-muted mb-0">
                  Add your first doctor from the form above.
                </p>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default DoctorsPage;
